    slot_type_id   = "AMAZON.AlphaNumeric"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What type of pizza would you like to order?"
            }
          }
        }
        max_retries = 2
      }
    }
  }

  # Slot 2: Quantity (The follow-up question)
  slot {
    name           = "Quantity"
    slot_type_id   = "AMAZON.Number"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "How many pizzas would you like?"
            }
          }
        }
        max_retries = 2
      }
    }
  }
}
