        "es:DescribeDomain",
        "es:DescribeDomains",
        "es:HTTPDelete",
        "es:HTTPGet",
        "es:HTTPHead",
        "es:HTTPPut",
        "es:HttpPost"
      ],
      "Resource": "*"
    },
