resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "firehose-stream-${random_id.suffix.hex}"

  # S3 configuration is required for OpenSearch destination (buffering/backup)
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.bucket.arn
    buffer_size        = 5
    buffer_interval    = 300
