# VPC and Subnet configuration
resource "aws_vpc" "eks_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "eks-fargate-vpc"
  }
}

resource "aws_subnet" "eks_subnet" {
  vpc_id     = aws_vpc.eks_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name                                                              = "eks-fargate-subnet"
    "kubernetes.io/cluster/${aws_eks_cluster.main.name}"              = "shared"
    "kubernetes.io/role/internal-elb"                                  = "1"
  }
}

# IAM Role for EKS Cluster
resource "aws_iam_role" "eks_cluster_role" {
  name = "eks-cluster-role"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# EKS Cluster
resource "aws_eks_cluster" "main" {
  name     = "eks-fargate-cluster"
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    subnet_ids = [aws_subnet.eks_subnet.id]
  }

  depends_on = [aws_iam_role_policy_attachment.eks_cluster_policy]
}

# IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "eks-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks-fargate-pods.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

# Attach the AmazonEKSFargatePodExecutionRolePolicy
resource "aws_iam_role_policy_attachment" "fargate_pod_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# EKS Fargate Profile for kube-system namespace
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = aws_eks_cluster.main.name
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = [aws_subnet.eks_subnet.id]

  selector {
    namespace = "kube-system"
  }
}

# Null Resource to patch CoreDNS
resource "null_resource" "patch_coredns" {
  depends_on = [aws_eks_fargate_profile.kube_system]

  provisioner "local-exec" {
    # This patch is commonly required to allow CoreDNS to run on Fargate by removing topology spread constraints
    command = <<EOT
      kubectl patch deployment coredns -n kube-system \n        --type json \n        -p '[{"op": "remove", "path": "/spec/template/spec/topologySpreadConstraints"}]' \n        --server=${aws_eks_cluster.main.endpoint} \n        --certificate-authority=<(echo ${aws_eks_cluster.main.certificate_authority[0].data} | base64 -d) \n        --token=$(aws eks get-token --cluster-name ${aws_eks_cluster.main.name} --query status.token --output text)
    EOT

    interpreter = ["/bin/bash", "-c"]
  }
}

