# Data source for the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Private Subnets
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "private-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group for EFS
resource "aws_security_group" "efs" {
  name_prefix = "efs-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port = 2049
    to_port   = 2049
    protocol  = "tcp"
    # Reference the EC2 SG to allow traffic only from the instances
    security_groups = [aws_security_group.ec2.id]
  }

  tags = {
    Name = "efs-sg"
  }
}

# Security Group for EC2
resource "aws_security_group" "ec2" {
  name_prefix = "ec2-sg-"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-sg"
  }
}

# EFS File System
resource "aws_efs_file_system" "shared" {
  tags = {
    Name = "shared-efs"
  }
}

# EFS Mount Targets (One per subnet for high availability)
resource "aws_efs_mount_target" "mount" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs.id]
}

# EC2 Instances
resource "aws_instance" "server" {
  count         = 2
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private[count.index].id

  vpc_security_group_ids = [aws_security_group.ec2.id]

  # User data script to install EFS utils and mount the file system
  user_data = <<-EOF
              #!/bin/bash
              yum install -y amazon-efs-utils
              mkdir -p /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs tls,_netdev" >> /etc/fstab
              mount -a -t efs
              EOF

  tags = {
    Name = "server-${count.index + 1}"
  }

  # Ensure the mount target exists before the instance is created
  depends_on = [aws_efs_mount_target.mount]
}

