provider "aws" {
  region = "us-east-1"
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow MSK traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_role" "msk_connect_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKConnectServiceRole"
  role       = aws_iam_role.msk_connect_role.name
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = slice(data.aws_subnets.default.ids, 0, 3)
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "PLAINTEXT"
      in_cluster    = true
    }
  }

  client_authentication {
    sasl {
      scram = false
    }
  }
}

resource "aws_mskconnect_custom_plugin" "example" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = "arn:aws:s3:::my-debezium-bucket"
      file_key   = "debezium.zip"
    }
  }
}

resource "aws_mskconnect_connector" "example" {
  name = "debezium-connector"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
    }
  }

  connector_configuration = {
    "connector.class" = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname" = "your-db-host"
    "database.port"     = "3306"
    "database.user"     = "user"
    "database.password" = "password"
    "database.server.name" = "my-server"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers[0]
    "database.history.kafka.topic" = "schema-changes.my-server"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers[0]

      vpc {
        subnets = slice(data.aws_subnets.default.ids, 0, 3)
        security_groups = [aws_security_group.msk_sg.id]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "PLAINTEXT"
  }

  plugin_location {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.example.arn
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

