resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "private" {
  vpc_id     = aws_vpc.autograder.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "autograder-private-subnet"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# S3 VPC Gateway Endpoint to allow storing results without internet access
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder.id
  service_name = "com.amazonaws.us-east-1.s3"

  route_table_ids = [
    aws_route_table.private.id
  ]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

resource "aws_s3_bucket" "results" {
  bucket = "autograder-results-${random_id.suffix.hex}"
}

resource "aws_security_group" "codebuild" {
  name        = "autograder-sg-${random_id.suffix.hex}"
  description = "Security group for autograder CodeBuild"
  vpc_id      = aws_vpc.autograder.id

  # No ingress or egress rules defined ensures strict isolation aside from VPC endpoints
  # VPC Gateway endpoints (S3) are handled by the Route Table, not Security Groups
  egress = []
  ingress = []
}

resource "aws_iam_role" "codebuild" {
  name = "autograder-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild" {
  role = aws_iam_role.codebuild.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.results.arn,
          "${aws_s3_bucket.results.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "autograder" {
  name         = "autograder-project-${random_id.suffix.hex}"
  service_role = aws_iam_role.codebuild.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:5.0"
    type         = "LINUX_CONTAINER"

    # Note: In a real-world scenario without internet, 
    # this image would need to be pulled from a private registry or cached locally.
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/example/student-repo.git"
  }

  # VPC Configuration places the build in the isolated private subnet
  vpc_config {
    vpc_id = aws_vpc.autograder.id

    subnets = [
      aws_subnet.private.id
    ]

    security_group_ids = [
      aws_security_group.codebuild.id
    ]
  }
}

