# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# IAM Role required by AWS Backup to manage EC2 backups
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the necessary managed policies for backup and restore
resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

resource "aws_iam_role_policy_attachment" "restore_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForRestores"
  role       = aws_iam_role.backup_role.name
}

# Create a Backup Vault to store the backups
resource "aws_backup_vault" "example" {
  name = "daily_backup_vault"
}

# Create a Backup Plan to schedule the backup (Daily at midnight)
resource "aws_backup_plan" "example" {
  name = "ec2_daily_midnight_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7 # Keep backups for 7 days
    }
  }
}

# Define a Selection to assign the EC2 instance to the Backup Plan based on a Tag
resource "aws_backup_selection" "example" {
  name         = "ec2_backup_selection"
  plan_id      = aws_backup_plan.example.id
  iam_role_arn = aws_iam_role.backup_role.arn

  resources = []

  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

# Create the EC2 Instance with the specific Tag to trigger the backup
resource "aws_instance" "example" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"

  tags = {
    Name   = "ExampleServer"
    Backup = "Daily"
  }
}

