              echo "<h1>Video Streaming Server ${count.index}</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "streaming-server-${count.index}"
  }
}

# Resource: AWS Load Balancer (ALB)
resource "aws_lb" "streaming" {
  name               = "streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Name = "streaming-alb"
  }
}

# Resource: AWS Load Balancing Target Group
resource "aws_lb_target_group" "streaming" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id
}

# Resource: AWS LB Listener
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming.arn
  }
}

# Resource: LB Target Group Attachment
resource "aws_lb_target_group_attachment" "web" {
  count            = 2
  target_group_arn = aws_lb_target_group.streaming.arn
  target_id        = aws_instance.web[count.index].id
  port             = 80
}

# Resource: AWS Route53 Zone
resource "aws_route53_zone" "primary" {
  name = "example-streaming.com"
}

# Resource: AWS Route53 Record
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example-streaming.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming.dns_name
    zone_id                = aws_lb.streaming.zone_id
    evaluate_target_health = true
  }
}
```

