resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My PostgreSQL Subnet Group"
  }
}

# Security Group to manage access
resource "aws_security_group" "postgres" {
  name        = "postgres-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "postgres" {
  description             = "KMS key for PostgreSQL encryption"
  deletion_window_in_days = 10
}

# Custom Parameter Group for PostgreSQL settings
resource "aws_db_parameter_group" "postgres" {
  name   = "postgres-15-params"
  family = "postgres15"

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

