resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "postgres-subnet-b"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_security_group" "main" {
  name        = "postgres-sg-${random_id.suffix.hex}"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

resource "aws_db_instance" "postgres" {
  identifier             = "postgres-instance-${random_id.suffix.hex}"
  engine                 = "postgres"
  engine_version         = "13.7"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20 // Gigabytes
  storage_type           = "gp2"
  db_name                = "mydb"
  username               = "postgresadmin"
  password               = random_password.db.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.main.id]
  backup_retention_period = 5
  backup_window          = "03:00-06:00"
  skip_final_snapshot    = true // Required for cleanup
  publicly_accessible    = false
}
```

