# Generate a random password for the database
resource "random_password" "db" {
  length  = 16
  special = false
}

# VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create two subnets in different availability zones
resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "My Aurora Subnet Group"
  }
}

# Security Group for the RDS Proxy (Allows ingress from anywhere/custom range for example)
resource "aws_security_group" "proxy" {
  name_prefix = "proxy-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for the RDS Database (Allows ingress from the Proxy SG only)
resource "aws_security_group" "db" {
  name_prefix = "db-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }
}

# Secrets Manager Secret for credentials
resource "aws_secretsmanager_secret" "db" {
  name = "aurora-cluster-secret"
}

resource "aws_secretsmanager_secret_version" "db" {
  secret_id = aws_secretsmanager_secret.db.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db.result
  })
}

# IAM Role for the RDS Proxy to access Secrets Manager
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow the role to read the specific secret
resource "aws_iam_policy" "secret_access" {
  name = "rds-proxy-secret-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db.arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_attach" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = aws_iam_policy.secret_access.arn
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "main" {
  engine                = "aurora-mysql"
  engine_version        = "5.7.mysql_aurora.2.11.2"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db.result
  db_subnet_group_name  = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db.id]
  skip_final_snapshot   = true
  apply_immediately     = true
}

# Aurora Cluster Instance
resource "aws_rds_cluster_instance" "main" {
  identifier         = "aurora-instance-1"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.main.engine
}

# RDS Proxy
resource "aws_db_proxy" "main" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_subnet_ids         = aws_subnet.subnets[*].id
  require_tls            = false
  idle_client_timeout    = 1800
  debug_logging          = false

  auth {
    secret_arn = aws_secretsmanager_secret.db.arn
    iam_auth   = "DISABLED"
  }
}

# Default Target Group for the Proxy
resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name
}

# Register the RDS Cluster as a target for the Proxy
resource "aws_db_proxy_target" "main" {
  db_proxy_name          = aws_db_proxy.main.name
  target_group_name      = "default"
  db_cluster_identifier = aws_rds_cluster.main.cluster_identifier
}
